mapper.select:
select album_id, deceased_id, image_url, thumbnail_url, description, sort_order, create_time
from mem_deceased_album
where album_id = #{albumId}

mapper.update:
update mem_deceased_album
image_url = #{imageUrl}, thumbnail_url = #{thumbnailUrl}, description = #{description}, sort_order = #{sortOrder},
where album_id = #{albumId}
